}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeFfiXmtpClient_lower(_ value: FfiXmtpClient) -> UInt64 {
    return FfiConverterTypeFfiXmtpClient.lower(value)
}






